export default class Equipment {
    id = 0;
    name = '';
    cost = 0;
    attribute = '';
    modifier = 0;
    description = '';
    animal = false;
    consumable = false;

    constructor ({
        id = 0,
        name = '',
        cost = 0,
        attribute = '',
        modifier = 0,
        description = '',
        animal = false,
        consumable = false
    }) {
        this.id = id;
        this.name = name;
        this.cost = cost;
        this.attribute = attribute;
        this.modifier = modifier;
        this.description = description;
        this.animal = animal;
        this.consumable = consumable;
    }
}
